        let neighbors = vec![x.wrapping_sub(1), x + 1];
        for &y in neighbors.iter() {
            if y < n {
                let diff = (nums[x] - nums[y]).abs();
                if diff < min_diff {
                    min_diff = diff;
                    best_y = y;
                } else if diff == min_diff {
